import { AppModule } from './src/app.module';
import { GamesController } from './src/games/games.controller';

async function test() {
  try {
    const moduleRef = await Test.createTestingModule({ imports: [AppModule] }).compile();
    const ctrl: any = moduleRef.get(GamesController, { strict: false });

    const routes = Object.getOwnPropertyNames(Object.getPrototypeOf(ctrl)).filter(m => m !== 'constructor');
    if (routes.length < 4) throw new Error('Faltan endpoints por implementar en el controlador.');

    let getPassed = false, postPassed = false, patchPassed = false, deletePassed = false;
    for (const r of routes) {
       try { if (ctrl[r]('123') === 'Juego 123') getPassed = true; } catch(e){}
       try { if (ctrl[r]({title: 'Zelda'}) === 'Creado Zelda') postPassed = true; } catch(e){}
       try { if (ctrl[r]('2', {title: 'Mario'}) === 'Actualizado 2') patchPassed = true; } catch(e){}
       try { if (ctrl[r]('99') === 'Eliminado 99') deletePassed = true; } catch(e){}
    }
    if (!getPassed) throw new Error('El GET por ID falla'); 
    if (!postPassed) throw new Error('El POST falla'); 
    if (!patchPassed) throw new Error('El PATCH falla');
    if (!deletePassed) throw new Error('El DELETE falla');
    console.log('Test pasado correctamente');
  } catch (e) { throw e; }
}
test();

