async function test() {
  try {
    const moduleRef = await Test.createTestingModule({ imports: [AppModule] }).compile();
    const service: any = moduleRef.get(ProductsService, { strict: false });

    let threw = false;
    try { service.findOneById(999); }
    catch (e) {
      threw = true;
      if (!(e instanceof HttpException)) throw new Error('El error lanzado no es un HttpException (o NotFoundException).');
      if (!e.message.includes("not found")) throw new Error('El mensaje de la excepción es incorrecto: ' + e.message);
    }
    if (!threw) throw new Error('Sigue retornando silenciosamente en lugar de lanzar la excepción');
    console.log('Test pasado correctamente');
  } catch (e) { throw e; }
}
test();

