import { Test } from '@nestjs/testing';
import { AppModule } from './src/app.module';
import { NotFoundException } from '@nestjs/common';
import * as fs from 'fs';

async function test() {
  try {
    if (!fs.existsSync('./src/courses/courses.controller.ts')) throw new Error('[VALIDATION_ERROR] No has creado el recurso Courses. Recomendación: nest g res courses --no-spec');
    const { CoursesController } = await import('./src/courses/courses.controller');
    const moduleRef = await Test.createTestingModule({ imports: [AppModule] }).compile();

    let controller: any;
    try { controller = moduleRef.get(CoursesController, { strict: false }); } catch(e) { throw new Error('[VALIDATION_ERROR] El CoursesController no está registrado en el módulo.'); }

    const allCourses = controller.findAll ? controller.findAll() : controller.getAll ? controller.getAll() : null;
    if (!Array.isArray(allCourses)) throw new Error('[VALIDATION_ERROR] El endpoint GET /courses no devuelve un arreglo (o no creaste el método findAll).');

    if (!controller.findOne) throw new Error('[VALIDATION_ERROR] Te falta el método findOne() para GET /courses/:id');
    let errorLanzado = false;
    try { controller.findOne(9999); } catch(e) { if (e instanceof NotFoundException) errorLanzado = true; }
    if (!errorLanzado) throw new Error('[VALIDATION_ERROR] El método findOne(9999) debería arrojar NotFoundException si no existe.');

    console.log('Test pasado correctamente');
  } catch (e) { throw e; }
}
test();
